import CardModel from "./CardModel.js";
import Player from "./Player.js";

class GameModel{
    constructor(playerCards, enemyCards) {
        // Nos aseguramos de que los arrays de cartas sean instancias de CardModel y no de Object
        this.playerCards = playerCards.map(card =>
            card instanceof CardModel ? card : new CardModel(card.id)
        );
        this.enemyCards = enemyCards.map(card =>
            card instanceof CardModel ? card : new CardModel(card.id)
        );

        this.currentPlayerCard = playerCards[0]; // Current player card
        this.currentEnemyCard = enemyCards[0]; // Current enemy card
        this.turn = 1; //La partida empieza en el turno 1

        //Podemos usar currentTurn = 2 para una partida acabada
        if(Math.random() < 0.5) {
            this.currentTurn = 0; //turno del jugador
        }else{
            this.currentTurn = 1; //turno del enemigo
        }

        //Desbloqueamos las cartas del jugador
        this.player = new Player();
        this.playerCards.forEach(card => {
            if (!this.player.getUnlockedCards().includes(card.getId())) {
                this.player.unlockCard(card.getId());
            }
        });
    }

    usePlayerAbility() {
        if(this.currentPlayerCard.abilityUsed) {
            throw new Error("La habilidad ya ha sido utilizada.");
        }
        switch (this.currentPlayerCard.passiveType) {
            case "Cura":
                this.currentPlayerCard.health += this.currentPlayerCard.passiveQuantity;
                break;
            case "Defensa":
                this.currentPlayerCard.isDefending = true;
                break;
            case "Fuerza":
                if(this.currentEnemyCard) {
                    this.currentEnemyCard.setHealth(this.currentEnemyCard.getHealth() - this.currentPlayerCard.passiveQuantity);
                } else {
                    throw new Error(this.currentEnemyCard + "Se requiere una carta objetivo para usar la habilidad de ataque.");
                }
                break;
            case "Nada":
                break;
        }
        this.currentPlayerCard.abilityUsed = true; // Marca la habilidad como utilizada    }
    }
    //Getters
    getPlayerCards() {
        return this.playerCards;
    }

    getEnemyCards() {
        return this.enemyCards;
    }

    getCurrentPlayerCard() {
        return this.currentPlayerCard;
    }

    getCurrentEnemyCard() {
        return this.currentEnemyCard;
    }

    getCurrentTurn() {
        return this.currentTurn;
    }

    getTurn() {
        return this.turn;
    }
    
    setNextEnemyCard() {
        if(this.enemyCards.length > 0) {
            this.currentEnemyCard = this.enemyCards[0]; // Cambia la carta activa del enemigo
        } else {
            this.currentEnemyCard = null; // No hay cartas del enemigo
        }
    }

}

export default GameModel;
